def strip_norm(s):
    return normalize_arabic(s)
def lcs_length(a, b):
    # dynamic programming LCS length on strings
    a = strip_norm(a)
    b = strip_norm(b)
    m, n = len(a), len(b)
    # Use only limited memory
    prev = [0] * (n+1)
    for i in range(1, m+1):
        curr = [0] * (n+1)
        ca = a[i-1]
        for j in range(1, n+1):
            if ca == b[j-1]:
                curr[j] = prev[j-1] + 1
            else:
                curr[j] = max(prev[j], curr[j-1])
        prev = curr
    return prev[n]

def sim_lcs_original_ratio(candidate):
    L = lcs_length(original, candidate)
    return L/len(strip_norm(original)), L

def sim_lcs_max_ratio(candidate):
    L = lcs_length(original, candidate)
    denom = max(len(strip_norm(original)), len(strip_norm(candidate)))
    return L/denom, L

